import React, { Component } from 'react';
import server from '../server';

class Cabinet extends Component {

  state = {
    loading: true,
    page: {}
  }

  componentDidMount() {

    const uri = this.props.route.location.pathname;

    fetch(server.uri+'page'+uri, server.params)
      .then(response => response.json())
      .then(data =>
        this.setState({
          loading: false,
          page: data
        })
      );
  }
  
  render() {

    if( this.state.loading )
      return <div className="loading"></div>;
    
    const page = this.state.page;
    
    return (
      <article className="page-infobase">
        <header className="main__header">
          <h1 className="main__title">{page.pagetitle}</h1>
        </header>

        <section className="main__content">
          <div dangerouslySetInnerHTML={{ __html: page.content }}></div>
          <br/>
          <p><img src="/assets/img/license.jpg" width="100%" alt="schedule"/></p>
          <br/>
          <div dangerouslySetInnerHTML={{ __html: page.extracontent }}></div>
        </section>
      </article>
    );
  }
}
export default Cabinet;



