import React, { Component } from 'react'
import axios from 'axios';
import { Link } from 'react-router-dom';
import Calendar from 'react-calendar'
import FormGroup from './FormGroup'
import Button from './Button'
import server from '../server'

class AsideRight extends Component {
  state = {
    form: {},
  }

  handleFormChange = e => {
    const input = e.target;
    this.setState({
      form: Object.assign(
          this.state.form,
          { [input.name]: input.value }
        )
    });
  }
  handleSubmit = e => {
    e.preventDefault();

    const data = new FormData(),
      form = this.state.form;

    data.append('title', 'Оставить заявку - с правого панеля');
    for( let k in form )
      data.append(k, form[k]);

    axios.post(server.uri+'request', data)
      .then(() => {
        this.setState({
          form: {}
        });

        this.props.handleNotify({
          type: 'success',
          text: 'Ваш запрос прошел успешно, мы вскоре свяжемся с Вами'
        });
      })
      .catch(() => {
        this.props.handleNotify({
          type: 'error',
          text: 'Что то пошло не так... попробуйте позже'
        });
      });
  }

  render() {

    const user = this.props.user,
      formLogin = this.props.formLogin,
      formLoginError = this.props.formLoginError,
      formLoginSettings = {
        required: true,
        handleChange: e => this.props.handleLoginChange(e),
      },
      card = this.props.card;
    
    return (
      <aside className="page-aside aside_right">

        <header>
          <form className={'login-form'+( this.props.formLoginLoading ? ' loading' : '' )+( user ? ' hide' : '' )} onSubmit={ e => this.props.handleLoginSubmit(e) }>

            <img src="/assets/imgs/profile-picture.svg" alt="Profile avatar"/>

            <FormGroup type="email" name="email" value={formLogin.email} error={formLoginError.email} placeholder="email" {...formLoginSettings}/>
            <FormGroup type="password" name="password" value={formLogin.password} error={formLoginError.password} placeholder="пароль" {...formLoginSettings}/>

            <div className="loginform__btns">
              <Button theme="success">Войти</Button>
              <a href="login/forget">забыли пароль?</a>
            </div>
          </form>

          <div className={'profile'+( user ? '' : ' hide' )}>
          
            <img src="/assets/imgs/profile-picture.svg" alt="Profile avatar"/>

            <div className="profile__info">
              <p className="profile__name">{user && user.email}</p>
              <p className="profile__id">№{user && user.id}</p>
            </div>

            <div className="profile__btn">
              <Button theme="success" handleClick={ this.props.handleSignout }>Выйти</Button>
            </div>
          </div>
        </header>

        <section>
          <a className="aside__phone" href={`tel:${this.props.phone2Href}`}>{ this.props.phone2 }</a>
        </section>

        <section>
          <a className="aside__title aside__title_blue" href="portal">Перейти в портал</a>
        </section>

        <section className="aside__calendar">
          <Calendar locale="ru-RU" value={ new Date() }/>
        </section>

        <section className="callback">
          <form onSubmit={this.handleSubmit}>

            <h3 className="aside__title aside__title_green">Оставить заявку</h3>

            <FormGroup class="aside__wrap" name="name" value={ this.state.name } placeholder="Ф.И.О." handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="position" value={ this.state.position } placeholder="Должность" handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="company" value={ this.state.company } placeholder="Компания" handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="email" value={ this.state.email } type="email" placeholder="Email" handleChange={ this.handleFormChange }/>
            <FormGroup class="aside__wrap" name="phone" value={ this.state.phone } type="tel" placeholder="Контактный номер" required handleChange={ this.handleFormChange }/>

            <div className="callback__btns">
              <Button theme="success">Отправить</Button>
            </div>
          </form>
        </section>

        <section>

          <h3 className="aside__title">Каталог / корзина запросов</h3>
          
          <div className="card_aside">
            <ul>
              { card.items.map( (v,i) => (
                <li key={i}>
                  <a href={ v.uri }>{ v.pagetitle }</a>
                  <Button theme="remove" handleClick={ () => this.props.handleCardRemove(v) }></Button>
                </li>
              ))}

              <li className={ 'card__empty'+(card.items.length ? ' hide' : '') }>
                <span>корзина пуста, </span>
                <Link to="/catalog">выбрать продукты</Link>
              </li>
            </ul>
          </div>
        </section>

        <footer>
          <div className="card_aside__btn">
            <Button theme="success" disabled={ !card.items.length }>Рассчитать запрос</Button>
          </div>
        </footer>
      </aside>
    );
  }
}
export default AsideRight;



